SELECT n.*
FROM notifications AS n
WHERE n.report_id = 'SPECIFIC_REPORT_ID' AND n.read_status = 1;

SELECT report_id, score_points, score_type
FROM report_scores
WHERE score_type = 1;

SELECT report_id
FROM incident_reports
WHERE field_id = (SELECT field_id FROM fields WHERE field_name = 'Witness Testimony');

SELECT incident_date, field_id, COUNT(*) AS report_count
FROM incident_reports
GROUP BY incident_date, field_id;

SELECT report_id, label, location, incident_date
FROM incident_reports
ORDER BY incident_date ASC;

SELECT notifications.*, incident_reports.* 
FROM notifications 
JOIN incident_reports ON notifications.report_id = incident_reports.report_id;

SELECT ir.report_id, u.user_name
FROM incident_reports ir
JOIN users u ON ir.reviewed_by = u.user_id;

SELECT report_id, status, update_date
FROM report_status
WHERE status = 'under review';

SELECT report_id, label 
FROM incident_reports 
ORDER BY report_id ASC;

SELECT users.user_name, users.role
FROM users
INNER JOIN report_scores ON users.user_id = report_scores.reviewed_by;

SELECT SUM(score_points) AS total_score
FROM report_scores
WHERE reviewed_by = 'u1';
